+                for (else_body) |s| analyzeStmtForLists(s, list_vars, list_aliases, allocator);
+            }
+        },
+        .if_stmt => |if_stmt| {
+            for (if_stmt.body) |s| analyzeStmtForLists(s, list_vars, list_aliases, allocator);
