+
+fn checkHeterogeneousAugAssign(
+    stmt: ast.Node,
+    list_vars: *hashmap_helper.StringHashMap(types.TypeHint),
+    heterogeneous_vars: *std.ArrayList([]const u8),
+    allocator: std.mem.Allocator,
